class Solution {
public:
    int maxCount(int m, int n, vector<vector<int>>& ops) {
        if (ops.empty()) return m * n;
        int mr = m, mc = n;
        for (auto& op : ops) { mr = min(mr, op[0]); mc = min(mc, op[1]); }
        return mr * mc;
    }
};
